class Solution:
    def canMakeSquare(self, grid) -> bool:
        for r in range(2):
            for c in range(2):
                block = [grid[r][c], grid[r][c+1], grid[r+1][c], grid[r+1][c+1]]
                b_count = block.count('B')
                w_count = block.count('W')
                if b_count >= 3 or w_count >= 3:
                    return True
        return False

solutions.python:
class Solution:
    def canMakeSquare(self, grid) -> bool:
        for r in range(2):
            for c in range(2):
                b = sum(grid[r+dr][c+dc] == 'B' for dr in range(2) for dc in range(2))
                if b >= 3 or b <= 1:
                    return True
        return False

