var canMakeSquare = function(grid) {
    for (let r = 0; r < 2; r++) {
        for (let c = 0; c < 2; c++) {
            let b = 0;
            for (let dr = 0; dr < 2; dr++)
                for (let dc = 0; dc < 2; dc++)
                    if (grid[r+dr][c+dc] === 'B') b++;
            if (b >= 3 || b <= 1) return true;
        }
    }
    return false;
};
